#!/usr/bin/env python3
"""SQL Query CLI for multiple file formats."""

import argparse
import sys
from pathlib import Path

import pandas as pd
from database import CSVDatabase
from query_executor import SQLExecutor


def load_sql_query(sql_arg: str) -> str:
    sql_path = Path(sql_arg)
    if sql_path.exists():
        return sql_path.read_text()
    return sql_arg


def format_as_markdown(df) -> str:
    if df.empty:
        return ""

    headers = list(df.columns)
    lines = [
        "| " + " | ".join(str(h) for h in headers) + " |",
        "| " + " | ".join(["---"] * len(headers)) + " |",
    ]

    for _, row in df.iterrows():
        cells = ["NULL" if pd.isna(row[col]) else str(row[col]) for col in headers]
        lines.append("| " + " | ".join(cells) + " |")

    return "\n".join(lines)


def parse_sharded_arg(sharded_str: str) -> tuple:
    if '=' not in sharded_str:
        raise ValueError(f"Invalid --sharded format: '{sharded_str}'. Expected '<table_name>=<glob_pattern>'")
    table_name, pattern = sharded_str.split('=', 1)
    if not table_name.strip():
        raise ValueError(f"Empty table name in --sharded: '{sharded_str}'")
    if not pattern.strip():
        raise ValueError(f"Empty glob pattern in --sharded: '{sharded_str}'")
    return (table_name.strip(), pattern.strip())


def main():
    parser = argparse.ArgumentParser(description="Run SQL queries on CSV files")
    parser.add_argument('--data', required=True, help='Directory containing CSV files')
    parser.add_argument('--sql', required=True, help='SQL query or path to SQL file')
    parser.add_argument('--out', help='Output file path for CSV result')
    parser.add_argument('--sharded', action='append', default=[],
                       help='Sharded table definition: <table_name>=<glob_pattern>. Can be specified multiple times.')
    args = parser.parse_args()

    sharded_configs = []
    for sharded_arg in args.sharded:
        try:
            sharded_configs.append(parse_sharded_arg(sharded_arg))
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)

    if not Path(args.data).is_dir():
        print(f"Error: Data directory '{args.data}' does not exist", file=sys.stderr)
        sys.exit(1)

    try:
        sql = load_sql_query(args.sql)
    except Exception as e:
        print(f"Error loading SQL: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        db = CSVDatabase(args.data)
        if sharded_configs:
            db.load_sharded_tables(sharded_configs)
        if not db.tables:
            print("Error: No valid CSV files found in data directory", file=sys.stderr)
            sys.exit(1)
    except Exception as e:
        print(f"Error loading data: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        result = SQLExecutor(db).execute(sql)
        print(format_as_markdown(result))
        if args.out:
            result.to_csv(args.out, index=False)
    except Exception as e:
        print(f"Error executing query: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

"""SQL query parser using sqlparse."""

import re
import sqlparse
from sqlparse.sql import Identifier
from sqlparse.tokens import Keyword

_KEYWORDS = {'AND', 'OR', 'NOT', 'SELECT', 'FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER',
             'INNER', 'LEFT', 'RIGHT', 'FULL', 'JOIN', 'ON', 'BY', 'ASC', 'DESC',
             'OVER', 'PARTITION', 'ROWS', 'RANGE', 'PRECEDING', 'FOLLOWING', 'CURRENT', 'UNBOUNDED'}

_STOP_WORDS = {'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET', 'BY'}


def parse_query(sql: str) -> dict:
    stmt = sqlparse.parse(sql.strip())[0]
    return {
        'select': _parse_select(stmt),
        'from': _parse_from(stmt),
        'where': _extract_tokens(stmt, 'WHERE', _STOP_WORDS),
        'group_by': _parse_token_list(stmt, 'GROUP', _STOP_WORDS),
        'having': _extract_tokens(stmt, 'HAVING', _STOP_WORDS),
        'order_by': _parse_order_by(stmt),
        'limit': _find_number(stmt, 'LIMIT', ['OFFSET']),
        'offset': _find_number(stmt, 'OFFSET', ['LIMIT']),
        'window_functions': _parse_window_functions(stmt),
    }


def _extract_tokens(stmt, keyword: str, stop: set) -> str:
    in_clause = False
    parts = []
    for t in stmt.flatten():
        if t.ttype in Keyword:
            k = t.value.upper()
            if k == keyword:
                in_clause = True
                continue
            elif k in stop:
                in_clause = False
        if in_clause and t.value.strip():
            parts.append(t.value)
    return ' '.join(parts).strip()


def _parse_token_list(stmt, keyword: str, stop: set) -> list:
    items = []
    for t in stmt.flatten():
        if t.ttype in Keyword:
            if t.value.upper() == keyword:
                continue
            if t.value.upper() in stop:
                break
        v = t.value.strip()
        if v and v != ',' and v not in stop:
            items.append(v)
    return items


def _find_number(stmt, keyword: str, stop: set) -> int | None:
    in_clause = False
    for t in stmt.flatten():
        if t.ttype in Keyword:
            k = t.value.upper()
            if k == keyword:
                in_clause = True
                continue
            if k in stop:
                in_clause = False
        if in_clause and t.value.strip():
            val = t.value.strip()
            if val.isdigit() or (val.startswith('-') and val[1:].isdigit()):
                return int(val)
    return None


def _parse_select(stmt) -> tuple:
    selects, distinct = [], False
    in_select = False
    for t in stmt.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'SELECT':
                in_select = True
                continue
            elif v.upper() in _STOP_WORDS:
                in_select = False
                continue
        if in_select and v:
            if v.upper() == 'DISTINCT':
                distinct = True
            else:
                selects.append(v)
    return selects, distinct


def _parse_window_functions(stmt) -> list:
    window_funcs, current_expr = [], []
    in_select = False

    for token in stmt.flatten():
        v = token.value.strip()
        if token.ttype in Keyword:
            if v.upper() == 'SELECT':
                in_select = True
                continue
            elif v.upper() in _STOP_WORDS:
                in_select = False
                if current_expr:
                    wf = _extract_window_spec(''.join(current_expr).strip())
                    if wf:
                        window_funcs.append(wf)
                    current_expr = []
                continue

        if in_select:
            if v == ',':
                if current_expr:
                    wf = _extract_window_spec(''.join(current_expr).strip())
                    if wf:
                        window_funcs.append(wf)
                    current_expr = []
            else:
                current_expr.append(v + ' ')

    if current_expr:
        wf = _extract_window_spec(''.join(current_expr).strip())
        if wf:
            window_funcs.append(wf)

    return window_funcs


def _extract_window_spec(expr: str) -> dict | None:
    expr = expr.strip()

    over_empty = re.search(r'\bOVER\s*\(\s*\)', expr, re.IGNORECASE)
    if over_empty:
        func_m = re.match(r'^([^(]+)\s+OVER\s*\(\s*\)', expr, re.IGNORECASE)
        if func_m:
            return {'function': func_m.group(1).strip().upper(), 'partition_by': [], 'order_by': [], 'frame_clause': None}

    over_match = re.search(r'\bOVER\s*\(', expr, re.IGNORECASE)
    if over_match:
        start, depth = over_match.end(), 1
        end = start
        for i, c in enumerate(expr[start:]):
            if c == '(':
                depth += 1
            elif c == ')':
                depth -= 1
                if depth == 0:
                    end = start + i
                    break

        body = expr[start:end].strip()
        func_part = expr[:over_match.start()].strip()
        func_name = (re.match(r'^(.*?)(?:\s+OVER)', func_part, re.IGNORECASE) or type('', None, '')())
        func = func_name.group(1).strip() if func_name else func_part

        return _parse_window_body(body, func)

    return None


def _parse_window_body(window_body: str, func: str) -> dict:
    frame_clause = None

    m = re.search(r'(?:(ROWS|RANGE)\b.*)$', window_body, re.IGNORECASE)
    if m:
        frame_clause = m.group(0).strip()
        window_body_for_parse = window_body[:m.start()].strip()
    else:
        window_body_for_parse = window_body

    parsed = sqlparse.parse(f"SELECT {window_body_for_parse}")[0]
    partition_by, order_by = [], []

    in_p = False
    for t in parsed.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'PARTITION':
                in_p = True
                continue
            if v.upper() == 'BY':
                continue
            elif v.upper() in ['ORDER', 'ROWS', 'RANGE']:
                in_p = False
        if in_p and v and v != ',':
            partition_by.append(v.rstrip(','))

    in_o = False
    for t in parsed.flatten():
        v = t.value.strip()
        if t.ttype in Keyword:
            if v.upper() == 'ORDER':
                in_o = True
                continue
            if v.upper() == 'BY':
                continue
            elif v.upper() in ['ROWS', 'RANGE', 'PARTITION']:
                in_o = False
        if in_o:
            if v.upper() == 'DESC' and order_by:
                order_by[-1] = (order_by[-1][0], True)
            elif v.upper() == 'ASC' and order_by:
                order_by[-1] = (order_by[-1][0], False)
            elif v and v != ',':
                order_by.append((v.rstrip(','), False))

    return {'function': func.upper(), 'partition_by': partition_by, 'order_by': order_by, 'frame_clause': frame_clause}


def _parse_from(stmt) -> dict:
    result = {'main_table': None, 'joins': []}
    in_from, in_join, join_type = False, False, 'INNER'

    for token in stmt.tokens:
        if token.ttype in Keyword:
            v = token.value.upper()
            if v == 'FROM':
                in_from, in_join = True, False
            elif v in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
                join_type = v
            elif v == 'JOIN':
                in_join = True
            elif v in {'WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET'}:
                in_from = in_join = False
        elif (in_from or in_join) and isinstance(token, Identifier):
            table = token.get_name()
            if in_join:
                result['joins'].append({'table': table, 'type': join_type, 'alias': token.get_alias(), 'on_cols': []})
            elif result['main_table'] is None:
                result['main_table'] = table
    return result


def _parse_order_by(stmt) -> list:
    columns = []
    in_order = False
    for t in stmt.flatten():
        v = t.value.strip().upper() if t.value.strip() else ''
        if t.ttype in Keyword:
            if v == 'ORDER':
                in_order = True
                continue
            if v == 'BY':
                continue
            elif v in ['LIMIT', 'OFFSET']:
                in_order = False
        if in_order:
            if v == 'DESC' and columns:
                columns[-1] = (columns[-1][0], True)
            elif v == 'ASC' and columns:
                columns[-1] = (columns[-1][0], False)
            elif v and v != ',':
                columns.append((t.value.strip(), False))
    return columns


def extract_alias(expr: str) -> str | None:
    expr = expr.strip()
    if ' as ' in expr.lower():
        return expr.split('AS')[-1].strip().strip('"').strip("'")
    parts = expr.rsplit(' ', 1)
    if len(parts) == 2:
        alias = parts[1].strip('"').strip("'")
        if alias.upper() not in _KEYWORDS:
            try:
                float(alias)
                return None
            except ValueError:
                return alias
    return None


def find_join_key(where_expr: str, table1: str, table2: str) -> tuple | None:
    if not where_expr:
        return None
    for pattern in [
        rf'{table1}\.((\w+))\s*=\s*{table2}\.((\w+))',
        rf'{table2}\.((\w+))\s*=\s*{table1}\.((\w+))',
    ]:
        match = re.search(pattern, where_expr, re.IGNORECASE)
        if match:
            return (match.group(1), match.group(3))
    return None

"""SQL query executor for CSV data."""

import pandas as pd
from database import CSVDatabase
from query_parser import parse_query, extract_alias, find_join_key
from evaluator import SQLExpressionEvaluator
from window_functions import WindowSpec, compute_window_function, validate_window_spec, WindowFunctionError


class SQLExecutor:
    """Executes SQL queries on CSV data."""

    def __init__(self, db: CSVDatabase):
        self.db = db

    def execute(self, sql: str) -> pd.DataFrame:
        return self._build_query(parse_query(sql))

    def _build_query(self, plan: dict) -> pd.DataFrame:
        df = self._load_main_table(plan['from']['main_table'])
        select_cols = self._process_select_expressions(plan['select'][0], df)

        df = self._apply_joins(df, plan['from'], plan['where'])
        if plan['where']:
            df = self._apply_where(df, plan['where'])

        group_by = plan['group_by']
        having = plan['having']
        if group_by or having:
            df = self._apply_group_by(df, group_by, select_cols, having, plan['select'][1])

        if plan['select'][1]:
            df = self._apply_distinct(df, select_cols)

        df = self._apply_window_functions(df, plan.get('window_functions', []), select_cols)
        df = self._apply_order_by(df, plan['order_by'], select_cols)
        df = self._apply_limit_offset(df, plan['limit'], plan['offset'])
        return self._build_result(df, select_cols)

    def _load_main_table(self, table_name: str) -> pd.DataFrame:
        df = self.db.get_table(table_name)
        if df is None:
            raise ValueError(f"Table '{table_name}' not found")
        return df.copy()

    def _process_select_expressions(self, select_list: list, df: pd.DataFrame) -> list:
        select_cols = []
        for expr in select_list:
            expr = expr.strip()
            upper = expr.upper()
            col = expr.split('.')[-1]

            if upper.startswith('COUNT('):
                inner = expr[6:-1].strip()
                col = '__count_all__' if inner == '*' else inner.split('.')[-1]
                alias = extract_alias(expr) or f'count_{len(select_cols)}'
            elif upper.startswith(('SUM(', 'MIN(', 'MAX(')):
                alias = extract_alias(expr) or f'{upper[:3].lower()}_{len(select_cols)}'
            elif 'OVER' in upper:
                alias = extract_alias(expr) or f'window_{len(select_cols)}'
                col = None
            else:
                alias = extract_alias(expr) or col

            agg_type_map = {'SUM': 'sum', 'MIN': 'min', 'MAX': 'max', 'COUNT': 'count'}
            agg_type = next((agg_type_map[f] for f in agg_type_map if upper.startswith(f'{f}(')), None)
            select_cols.append((alias, expr, agg_type, col))
        return select_cols

    def _apply_joins(self, df: pd.DataFrame, from_clause: dict, where_expr: str) -> pd.DataFrame:
        for join_info in from_clause.get('joins', []):
            join_df = self.db.get_table(join_info['table'])
            if join_df is None:
                raise ValueError(f"Table '{join_info['table']}' not found")
            join_key = find_join_key(where_expr, from_clause['main_table'], join_info['table'])
            how = join_info.get('type') or 'INNER'
            kwargs = {'left_on': join_key[0], 'right_on': join_key[1]} if join_key else {}
            df = pd.merge(df, join_df, how=how, suffixes=('_x', '_y'), **kwargs)
        return df

    def _apply_where(self, df: pd.DataFrame, where_expr: str) -> pd.DataFrame:
        evaluator = SQLExpressionEvaluator(self.db.tables)
        mask = df.apply(lambda row: evaluator.evaluate(where_expr, row), axis=1)
        return df[mask].copy()

    def _apply_group_by(self, df: pd.DataFrame, group_by: list, select_cols: list,
                       having: str, distinct: bool) -> pd.DataFrame:
        group_cols = [g.split('.')[-1] for g in group_by]
        existing = [c for c in group_cols if c in df.columns]
        if not existing:
            raise ValueError("No valid GROUP BY columns found")

        agg_dict = {}
        has_count_all = False
        for _, _, agg_type, col in select_cols:
            if agg_type == 'count' and col == '__count_all__':
                has_count_all = True
            elif agg_type and col in df.columns:
                agg_dict[col] = agg_type

        if agg_dict:
            grouped = df.groupby(existing, as_index=False).agg(agg_dict)
            new_cols = []
            for col in grouped.columns:
                if col in existing:
                    new_cols.append(col)
                else:
                    for alias, _, _, c in select_cols:
                        if c == col:
                            new_cols.append(alias)
                            break
                    else:
                        new_cols.append(col)
            grouped.columns = new_cols
            df = grouped
        elif has_count_all:
            df = df.groupby(existing, as_index=False).size()
            df.columns = existing + ['count']
        else:
            raise ValueError("No valid aggregate in SELECT with GROUP BY")

        if having and group_by:
            evaluator = SQLExpressionEvaluator(self.db.tables)
            df = df[df.apply(lambda row: evaluator.evaluate(having, row), axis=1)]

        return df

    def _apply_distinct(self, df: pd.DataFrame, select_cols: list) -> pd.DataFrame:
        cols = [alias for alias, _, agg_type, col in select_cols
                if alias in df.columns and agg_type is None]
        return df[cols].drop_duplicates() if cols else df

    def _apply_window_functions(self, df: pd.DataFrame, window_funcs: list,
                                select_cols: list) -> pd.DataFrame:
        if not window_funcs:
            return df

        for wf in window_funcs:
            spec = WindowSpec(wf['function'], wf['partition_by'], wf['order_by'], wf.get('frame_clause'))
            validate_window_spec(spec)
            result = compute_window_function(df, spec)

            alias = next((a for a, e, _, _ in select_cols if wf['function'] in e.upper() and 'OVER' in e.upper()),
                        f"window_{len([c for c in df.columns if c.startswith('window_')])}")
            df[alias] = result

        return df

    def _apply_order_by(self, df: pd.DataFrame, order_by: list, select_cols: list) -> pd.DataFrame:
        if not order_by:
            return df

        sort_cols = []
        ascending = []
        for col, desc in order_by:
            name = col.split('.')[-1]
            if name in df.columns:
                sort_cols.append(name)
                ascending.append(not desc)
            else:
                for alias, _, _, c in select_cols:
                    if alias == name:
                        sort_cols.append(alias)
                        ascending.append(not desc)
                        break

        if sort_cols:
            df = df.sort_values(by=sort_cols, ascending=ascending)
        return df

    def _apply_limit_offset(self, df: pd.DataFrame, limit: int, offset: int) -> pd.DataFrame:
        if limit is not None:
            return df.iloc[offset:offset+limit] if offset else df.head(limit)
        if offset is not None:
            return df.iloc[offset:]
        return df

    def _build_result(self, df: pd.DataFrame, select_cols: list) -> pd.DataFrame:
        result_cols = []
        for alias, _, agg_type, col in select_cols:
            if alias in df.columns:
                result_cols.append(alias)
            elif agg_type == 'count' and col == '__count_all__' and 'count' in df.columns:
                result_cols.append('count')

        if not result_cols:
            result_cols = [c for c in df.columns if not c.endswith(('_x', '_y'))]

        return df[result_cols]

"""Window function computation engine for SQL analytics."""

import pandas as pd
import numpy as np
from typing import List, Dict, Tuple, Optional, Callable
from enum import Enum
from errors import WindowSpecError, FrameClauseError


class FrameType(Enum):
    ROWS = "rows"
    RANGE = "range"


class FrameBound(Enum):
    UNBOUNDED_PRECEDING = "unbounded_preceding"
    UNBOUNDED_FOLLOWING = "unbounded_following"
    CURRENT_ROW = "current_row"


class WindowSpec:
    """Represents a window specification."""

    def __init__(self, function: str, partition_by: List[str], order_by: List[Tuple[str, bool]],
                 frame_clause: Optional[str] = None):
        self.function = function.upper()
        self.partition_by = partition_by
        self.order_by = order_by  # List of (column, ascending) tuples
        self.frame_clause = frame_clause
        self.frame_type = None
        self.frame_start = None
        self.frame_end = None
        self._parse_frame_clause()

    def _parse_frame_clause(self):
        """Parse the frame clause into type and bounds."""
        if not self.frame_clause:
            # Default: RANGE UNBOUNDED PRECEDING
            self.frame_type = FrameType.RANGE
            self.frame_start = FrameBound.UNBOUNDED_PRECEDING
            self.frame_end = FrameBound.CURRENT_ROW
            return

        clause = self.frame_clause.upper()

        if 'ROWS' in clause:
            self.frame_type = FrameType.ROWS
        elif 'RANGE' in clause:
            self.frame_type = FrameType.RANGE

        # Parse bounds
        if 'UNBOUNDED PRECEDING' in clause:
            if self.frame_start is None:
                self.frame_start = FrameBound.UNBOUNDED_PRECEDING
        if 'CURRENT ROW' in clause:
            if self.frame_start is None:
                self.frame_start = FrameBound.CURRENT_ROW
            if self.frame_end is None:
                self.frame_end = FrameBound.CURRENT_ROW
        if 'BETWEEN' in clause:
            parts = clause.split('BETWEEN')[1].split('AND')
            if len(parts) == 2:
                start_str = parts[0].strip()
                end_str = parts[1].strip()

                self.frame_start = self._parse_bound(start_str)
                self.frame_end = self._parse_bound(end_str)

        # Default frame if not BETWEEN
        if self.frame_start is None and self.frame_end is None:
            if 'UNBOUNDED PRECEDING' in clause:
                self.frame_start = FrameBound.UNBOUNDED_PRECEDING
                self.frame_end = FrameBound.CURRENT_ROW
            else:
                # Default
                self.frame_start = FrameBound.UNBOUNDED_PRECEDING
                self.frame_end = FrameBound.CURRENT_ROW

    def _parse_bound(self, bound_str: str) -> FrameBound:
        """Parse a single bound string."""
        bound_upper = bound_str.upper()
        if 'UNBOUNDED PRECEDING' in bound_upper:
            return FrameBound.UNBOUNDED_PRECEDING
        elif 'CURRENT ROW' in bound_upper:
            return FrameBound.CURRENT_ROW
        elif 'UNBOUNDED FOLLOWING' in bound_upper:
            return FrameBound.UNBOUNDED_FOLLOWING
        return FrameBound.CURRENT_ROW


class WindowFunctionError(Exception):
    """Base exception for window function errors."""
    pass


class InvalidWindowSpecError(WindowFunctionError):
    """Invalid window specification."""
    pass


class FrameError(WindowFunctionError):
    """Frame clause error."""
    pass


class NestedWindowError(WindowFunctionError):
    """Nested window functions not supported."""
    pass


def raise_window_error(error_type: str, message: str):
    """Raise a window-related error using the error code system."""
    errors = {
        'INVALID_WINDOW_SPEC': WindowSpecError,
        'FRAME_ERROR': FrameClauseError,
        'NESTED_WINDOW_ERROR': WindowSpecError,  # fallback
    }
    error_class = errors.get(error_type)
    if not error_class:
        raise WindowSpecError(f"Unknown window error: {message}")
    raise error_class(message)


def compute_window_function(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """
    Compute a window function over a DataFrame.

    Args:
        df: Input DataFrame
        spec: Window specification

    Returns:
        Series with window function results aligned to input rows
    """
    if spec.partition_by:
        # Group by partition columns
        group_keys = [c for c in spec.partition_by if c in df.columns]
        if not group_keys:
            # No valid partition columns - treat as single partition
            return _compute_window_for_partition(df, spec)

        grouped = df.groupby(group_keys, group_keys=False, sort=False)

        # Apply window function to each partition
        results = []
        for _, group in grouped:
            result = _compute_window_for_partition(group.reset_index(drop=True), spec)
            results.append(result)

        # Combine results maintaining original order
        result_series = pd.concat(results, ignore_index=True)
        return result_series.reindex(df.index)
    else:
        # No partition - single window
        return _compute_window_for_partition(df, spec)


def _compute_window_for_partition(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """Compute window function for a single partition."""
    if df.empty:
        return pd.Series([], dtype=float)

    func_upper = spec.function

    # Handle ranking functions
    if func_upper in ['ROW_NUMBER', 'RANK', 'DENSE_RANK']:
        return _compute_ranking_function(df, spec)

    # Handle aggregate window functions
    if func_upper in ['SUM', 'AVG', 'MIN', 'MAX', 'COUNT']:
        return _compute_aggregate_window(df, spec)

    raise InvalidWindowSpecError(f"Unsupported window function: {spec.function}")


def _compute_ranking_function(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """Compute ranking window functions (ROW_NUMBER, RANK, DENSE_RANK)."""
    if not spec.order_by:
        # No ORDER BY - all rows get rank 1
        if spec.function == 'ROW_NUMBER':
            return pd.Series(range(1, len(df) + 1), index=df.index)
        elif spec.function == 'RANK':
            return pd.Series(1, index=df.index)
        elif spec.function == 'DENSE_RANK':
            return pd.Series(1, index=df.index)

    # Sort by order_by columns
    sort_cols = [col for col, _ in spec.order_by if col in df.columns]
    ascending = [not desc for _, desc in spec.order_by]

    if sort_cols:
        df_sorted = df.sort_values(by=sort_cols, ascending=ascending, kind='mergesort')
    else:
        df_sorted = df.copy()

    # Compute ranks based on order_by values
    if spec.function == 'ROW_NUMBER':
        # Simple row number
        result = pd.Series(range(1, len(df_sorted) + 1), index=df_sorted.index)
    elif spec.function == 'RANK':
        # Standard rank with gaps
        order_values = _get_order_values(df_sorted, spec.order_by)
        ranks = _compute_standard_ranks(order_values)
        result = pd.Series(ranks, index=df_sorted.index)
    elif spec.function == 'DENSE_RANK':
        # Dense rank without gaps
        order_values = _get_order_values(df_sorted, spec.order_by)
        ranks = _compute_dense_ranks(order_values)
        result = pd.Series(ranks, index=df_sorted.index)

    # Return to original order
    return result.reindex(df.index)


def _get_order_values(df: pd.DataFrame, order_by: List[Tuple[str, bool]]) -> List:
    """Get sorted values for ranking computation."""
    if not order_by:
        return list(range(len(df)))

    cols = [col for col, _ in order_by if col in df.columns]
    if not cols:
        return list(range(len(df)))

    # Convert to tuples for comparison
    ascending = [not desc for _, desc in order_by]
    sort_df = df[cols].sort_values(by=cols, ascending=ascending)
    return list(sort_df.itertuples(index=False, name=None))


def _compute_standard_ranks(values: List) -> List[int]:
    """Compute standard SQL RANK values with gaps."""
    if not values:
        return []

    ranks = []
    current_rank = 1
    for i, val in enumerate(values):
        if i > 0 and val != values[i - 1]:
            current_rank = i + 1
        ranks.append(current_rank)
    return ranks


def _compute_dense_ranks(values: List) -> List[int]:
    """Compute dense rank values without gaps."""
    if not values:
        return []

    ranks = []
    current_rank = 1
    unique_vals = []

    for val in values:
        if not unique_vals or val != unique_vals[-1]:
            unique_vals.append(val)

    val_to_rank = {val: i + 1 for i, val in enumerate(unique_vals)}

    for val in values:
        ranks.append(val_to_rank[val])

    return ranks


def _compute_aggregate_window(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """Compute aggregate window functions (SUM, AVG, MIN, MAX, COUNT)."""
    if not spec.order_by and spec.frame_type != FrameType.ROWS:
        # No ORDER BY - simple aggregate over partition
        return _compute_simple_aggregate(df, spec)

    # With ORDER BY - compute frame-based aggregate
    return _compute_frame_aggregate(df, spec)


def _compute_simple_aggregate(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """Compute aggregate without frame (over entire partition)."""
    col_name = _get_function_column(spec)

    if col_name is None or col_name not in df.columns:
        if spec.function == 'COUNT':
            # COUNT(*) over partition
            return pd.Series(len(df), index=df.index)
        raise InvalidWindowSpecError(f"Column '{col_name}' not found for {spec.function}")

    col = df[col_name]

    if spec.function == 'SUM':
        result = col.sum()
    elif spec.function == 'AVG':
        result = col.mean()
    elif spec.function == 'MIN':
        result = col.min()
    elif spec.function == 'MAX':
        result = col.max()
    elif spec.function == 'COUNT':
        result = col.count()
    else:
        raise InvalidWindowSpecError(f"Unsupported aggregate function: {spec.function}")

    return pd.Series(result, index=df.index)


def _compute_frame_aggregate(df: pd.DataFrame, spec: WindowSpec) -> pd.Series:
    """Compute aggregate with frame specification (running totals, etc.)."""
    sort_cols = [col for col, _ in spec.order_by if col in df.columns]
    ascending = [not desc for _, desc in spec.order_by]

    if sort_cols:
        df_sorted = df.sort_values(by=sort_cols, ascending=ascending, kind='mergesort')
    else:
        df_sorted = df.copy()

    col_name = _get_function_column(spec)

    results = []
    n = len(df_sorted)

    for i in range(n):
        # Determine frame boundaries
        start_idx, end_idx = _get_frame_indices(i, df_sorted, spec)

        if col_name and col_name in df_sorted.columns:
            frame_data = df_sorted.iloc[start_idx:end_idx + 1][col_name]
        else:
            # COUNT(*) - all rows in frame
            frame_data = pd.Series([1] * (end_idx - start_idx + 1))

        if spec.function == 'SUM':
            val = frame_data.sum()
        elif spec.function == 'AVG':
            val = frame_data.mean()
        elif spec.function == 'MIN':
            val = frame_data.min()
        elif spec.function == 'MAX':
            val = frame_data.max()
        elif spec.function == 'COUNT':
            val = len(frame_data)
        else:
            raise InvalidWindowSpecError(f"Unsupported aggregate function: {spec.function}")

        results.append(val)

    result_series = pd.Series(results, index=df_sorted.index)
    return result_series.reindex(df.index)


def _get_frame_indices(current_idx: int, df: pd.DataFrame, spec: WindowSpec) -> Tuple[int, int]:
    """Get frame start and end indices for a given row."""
    n = len(df)

    if spec.frame_type == FrameType.ROWS:
        # ROWS frame uses physical row positions
        start = _resolve_row_bound(spec.frame_start, current_idx, n)
        end = _resolve_row_bound(spec.frame_end, current_idx, n)
    else:
        # RANGE frame uses logical value positions
        # For RANGE, all rows with the same ORDER BY values are in the same peer group
        sort_cols = [col for col, _ in spec.order_by if col in df.columns]
        if not sort_cols:
            start = 0
            end = n - 1
        else:
            # Find all rows with ORDER BY values equal to current row
            current_vals = df.iloc[current_idx][sort_cols]
            peer_group = []
            for i in range(n):
                row_vals = df.iloc[i][sort_cols]
                if _values_equal(row_vals, current_vals):
                    peer_group.append(i)

            if not peer_group:
                start = current_idx
                end = current_idx
            else:
                # For RANGE UNBOUNDED PRECEDING, all rows up to current peer group
                start = 0
                end = peer_group[-1]

    return start, end


def _resolve_row_bound(bound: FrameBound, current_idx: int, n: int) -> int:
    """Resolve a ROWS frame bound to an actual index."""
    if bound == FrameBound.UNBOUNDED_PRECEDING:
        return 0
    elif bound == FrameBound.UNBOUNDED_FOLLOWING:
        return n - 1
    elif bound == FrameBound.CURRENT_ROW:
        return current_idx
    return current_idx


def _values_equal(vals1, vals2) -> bool:
    """Check if two sets of values are equal, handling NaN."""
    if isinstance(vals1, pd.Series):
        vals1 = vals1.values
    if isinstance(vals2, pd.Series):
        vals2 = vals2.values

    if len(vals1) != len(vals2):
        return False

    for v1, v2 in zip(vals1, vals2):
        if pd.isna(v1) and pd.isna(v2):
            continue
        if pd.isna(v1) or pd.isna(v2):
            return False
        if v1 != v2:
            return False

    return True


def _get_function_column(spec: WindowSpec) -> Optional[str]:
    """Extract the column name from the function call."""
    func_expr = spec.function

    # Remove function name
    if '(' in func_expr:
        inner = func_expr.split('(', 1)[1].rsplit(')', 1)[0].strip()
        if inner == '*':
            return None
        # Handle column references (with possible table prefix)
        if '.' in inner:
            return inner.split('.')[-1]
        return inner

    return None


def validate_window_spec(spec: WindowSpec) -> None:
    """Validate a window specification."""
    if not spec.function:
        raise InvalidWindowSpecError("Window function name is required")

    func_upper = spec.function.upper()
    valid_functions = ['SUM', 'AVG', 'MIN', 'MAX', 'COUNT', 'ROW_NUMBER', 'RANK', 'DENSE_RANK']
    if func_upper not in valid_functions:
        raise InvalidWindowSpecError(f"Invalid window function: {spec.function}")

    # Validate frame clause
    if spec.frame_clause:
        if 'ROWS' not in spec.frame_clause.upper() and 'RANGE' not in spec.frame_clause.upper():
            raise FrameError(f"Invalid frame clause: {spec.frame_clause}")

"""Error handling for SQL query engine."""


class SQLError(Exception):
    """Base exception for SQL errors."""

    def __init__(self, code: int, group: str, message: str):
        self.code = code
        self.group = group
        self.message = message
        super().__init__(f"[{group}] (code {code}): {message}")


