    def __init__(self, message: str):
        super().__init__(FRAME_ERROR, "WINDOW_ERROR", message)


class NestedWindowFunctionError(SQLError):
    """Nested window functions are not supported."""

    def __init__(self, message: str = "Nested window functions are not supported"):
        super().__init__(NESTED_WINDOW_ERROR, "WINDOW_ERROR", message)

"""Database layer for SQL query CLI supporting multiple file formats."""

import sys
from glob import glob
from pathlib import Path
from typing import Dict, Optional
import pandas as pd
import gzip
import bz2


SUPPORTED_FORMATS = {'.csv', '.parquet', '.tsv', '.json', '.jsonl'}
COMPRESSED_EXTENSIONS = {'.gz', '.bz2'}


def _read_file(filepath: Path, fmt: str, comp_ext: Optional[str]) -> pd.DataFrame:
    """Read a file based on its format and compression."""
    opener = {
        '.gz': gzip.open,
        '.bz2': bz2.open,
        None: open,
    }[comp_ext]

    read_kwargs = {'encoding': 'utf-8'} if comp_ext else {}

    if fmt == '.csv':
        with opener(filepath, 'rt', **read_kwargs) as f:
            return pd.read_csv(f)
    elif fmt == '.parquet':
        return pd.read_parquet(filepath)
    elif fmt == '.tsv':
        with opener(filepath, 'rt', **read_kwargs) as f:
            return pd.read_csv(f, sep='\t')
    elif fmt == '.json':
        with opener(filepath, 'rt', **read_kwargs) as f:
            return pd.read_json(f, lines=False)
    elif fmt == '.jsonl':
        with opener(filepath, 'rt', **read_kwargs) as f:
            return pd.read_json(f, lines=True)
    return pd.DataFrame()


def _get_format_from_path(filepath: Path) -> tuple:
    for comp in COMPRESSED_EXTENSIONS:
        if filepath.name.endswith(comp):
            name_without_comp = filepath.name[:-(len(comp))]
            for fmt in SUPPORTED_FORMATS:
                if name_without_comp.endswith(fmt):
                    return fmt, comp
            return None, None
    for fmt in SUPPORTED_FORMATS:
        if filepath.name.endswith(fmt):
            return fmt, None
    return None, None


def _extract_base_name(filepath: Path) -> str:
    """Extract base name from filepath, removing format and compression extensions."""
    name = filepath.name
    for ext in COMPRESSED_EXTENSIONS:
        if name.endswith(ext):
            name = name[:-(len(ext))]
            break
    for fmt in SUPPORTED_FORMATS:
        if name.endswith(fmt):
            name = name[:-(len(fmt))]
            break
    return name


def _load_files_from_paths(filepaths: list) -> Dict[str, pd.DataFrame]:
    """Load multiple files, grouping by base name."""
    file_groups: Dict[str, list] = {}

    for fp in map(Path, filepaths):
        fmt, comp = _get_format_from_path(fp)
        if fmt:
            base = _extract_base_name(fp)
            file_groups.setdefault(base, []).append((fp, fmt, comp))

    tables = {}
    for base_name, files in file_groups.items():
        table_name = base_name.replace('.', '_')
        dataframes = []

        for fp, fmt, comp in files:
            try:
                df = _read_file(fp, fmt, comp)
                if not df.empty:
                    dataframes.append(df)
            except Exception as e:
                print(f"Warning: Could not load {fp}: {e}", file=sys.stderr)

        if not dataframes:
            continue

        first = dataframes[0]
        for df in dataframes[1:]:
            if list(df.columns) != list(first.columns):
                print(f"Warning: File {fp.name} has different columns", file=sys.stderr)
            else:
                first = pd.concat([first, df], ignore_index=True)

        tables[table_name] = first

    return tables


class CSVDatabase:
    """Manages multiple file format files as database tables."""

    def __init__(self, data_dir: str):
        self.data_dir = Path(data_dir)
        self.tables: Dict[str, pd.DataFrame] = {}
        self._load_tables()

    def _load_tables(self):
        """Load all supported files from data directory."""
        filepaths = []
        for ext in SUPPORTED_FORMATS:
            filepaths.extend(self.data_dir.rglob(f"*{ext}"))
            for comp_ext in COMPRESSED_EXTENSIONS:
                filepaths.extend(self.data_dir.rglob(f"*{ext}{comp_ext}"))
        self.tables = _load_files_from_paths(filepaths)

    def get_table(self, name: str) -> Optional[pd.DataFrame]:
        return self.tables.get(name)

    def load_sharded_tables(self, sharded_configs: list):
        """Load sharded tables from glob patterns."""
        for table_name, pattern in sharded_configs:
            filepaths = sorted(glob(pattern))
            if not filepaths:
                self.tables[table_name] = pd.DataFrame()
                continue
            tables = _load_files_from_paths(filepaths)
            self.tables[table_name] = list(tables.values())[0] if tables else pd.DataFrame()

"""SQL expression evaluator for WHERE and HAVING clauses."""

import re
import pandas as pd


class SQLExpressionEvaluator:
    """Evaluates boolean expressions for WHERE and HAVING clauses."""

    def __init__(self, tables):
        self.tables = tables

    def evaluate(self, expr: str, row: pd.Series) -> bool:
        if not expr or not expr.strip():
            return True
        expr = self._replace_operators(expr.strip())
        expr = self._handle_like(expr)
        expr = self._process_parentheses(expr, row)
        expr = self._process_not(expr, row)
        return self._safe_eval(expr, row)

    def _replace_operators(self, expr: str) -> str:
        expr = expr.replace('<>', '!=')
        return (expr.replace('AND', 'and').replace('OR', 'or').replace('NOT', 'not')
                  .replace('TRUE', 'True').replace('FALSE', 'False').replace('NULL', 'None'))

    def _handle_like(self, expr: str) -> str:
        def convert_like(m):
            left = m.group(1).strip("'\"")
            pattern = m.group(2).strip("'\"").replace('%', '.*').replace('_', '.')
            return 'True' if re.match(pattern + '$', left, re.IGNORECASE) else 'False'
        return re.sub(r'([^"\']*?)\s+LIKE\s+([^"\']*)', convert_like, expr, flags=re.IGNORECASE)

    def _process_parentheses(self, expr: str, row: pd.Series) -> str:
        while '(' in expr:
            start = expr.rfind('(')
            end = expr.find(')', start)
            if end == -1:
                break
            result = self.evaluate(expr[start+1:end], row)
            expr = expr[:start] + ('True' if result else 'False') + expr[end+1:]
        return expr

    def _process_not(self, expr: str, row: pd.Series) -> str:
        for m in re.finditer(r'\bNOT\s+(.+?)(?:\s|AND|OR|$)', expr, re.IGNORECASE):
            result = self.evaluate(m.group(1), row)
            expr = expr.replace(m.group(0), 'False' if result else 'True')
        return expr

    def _safe_eval(self, expr: str, row: pd.Series) -> bool:
        def replace_column(m):
            col = m.group(1).split('.')[-1]
            if col not in row.index:
                return 'None'
            val = row[col]
            if pd.isna(val):
                return 'None'
            if isinstance(val, str):
                return f"'{val}'"
            return str(val) if isinstance(val, (int, float)) else 'None'
        expr = re.sub(r'\b(\w+)\b', replace_column, expr)
        try:
            return bool(eval(expr, {"__builtins__": {}}, {}))
        except:
            return False

