    """Parse FROM clause, handling derived tables (subqueries)."""
    result = {'main_table': None, 'joins': [], 'derived_tables': []}
    in_from, in_join, join_type = False, False, 'INNER'

    tokens = list(stmt.tokens)

    for idx, token in enumerate(tokens):
